  if (reject.some(k => title.includes(k))) {
    return { json: { ...job, rule_tier: 'D', rule_score: 10, needs_llm: false } };
  }

  // Instant high-score: perfect title match
  const perfect = ['learning development manager', 'l&d manager', 'head of l&d', 'head of learning', 'l&d business partner', 'talent development manager', 'lecturer in human resource', 'senior lecturer management', 'lecturer hrm', 'organisational development manager', 'people development manager'];
  if (perfect.some(k => title.includes(k))) {
    return { json: { ...job, rule_tier: 'A', rule_score: 85, needs_llm: true } };
  }

  return { json: { ...job, rule_tier: null, rule_score: null, needs_llm: true } };
});

