// Parse Claude response and calculate composite score
const items = $input.all();
const tenantId = items[0]?.json?.tenant_id || '';
return items.map(item => {
  try {
    const response = item.json;
    const content = response.content?.[0]?.text || '{}';
    // Extract JSON from response (handle markdown code blocks)
    const jsonMatch = content.match(/\{[\s\S]*\}/);
    const scores = JSON.parse(jsonMatch ? jsonMatch[0] : '{}');

    const composite = (
      (scores.title_match || 0) * 0.25 +
      (scores.seniority_match || 0) * 0.20 +
      (scores.location_match || 0) * 0.15 +
      (scores.salary_match || 0) * 0.15 +
      (scores.skills_match || 0) * 0.15 +
      (scores.sector_match || 0) * 0.10
    ) * 10;

    let tier;
    if (composite >= 80) tier = 'A';
    else if (composite >= 65) tier = 'B';
    else if (composite >= 45) tier = 'C';
    else tier = 'D';

    const tokens = (response.usage?.input_tokens || 0) + (response.usage?.output_tokens || 0);
    const cost = tokens * 0.000001; // Haiku pricing approx

    return { json: { ...scores, composite_score: Math.round(composite * 100) / 100, tier, tokens_used: tokens, cost_usd: cost, scoring_method: 'haiku', model_used: 'claude-3-5-haiku' } };
  } catch (e) {
    return { json: { composite_score: 50, tier: 'C', reasoning: 'Parse error: ' + e.message, scoring_method: 'haiku_error', model_used: 'claude-3-5-haiku', tokens_used: 0, cost_usd: 0 } };
  }
});

